1	import { useEffect, useRef, useState, useCallback } from 'react'
2	import { useQueryClient } from '@tanstack/react-query'
3	import { API_BASE } from '@/config/api'
4	import type { WSMessage, WSClientMessage, ParsedEvent } from '@/types'
5	
6	const WS_URL = `ws://${window.location.host}/api/events/stream`
7	
8	// Fetch log level from server once on module load
9	let logLevel: 'debug' | 'trace' | 'none' = 'none'
10	fetch(`${API_BASE}/health`)
11	  .then((r) => r.json())
12	  .then((data) => {
13	    const level = (data.logLevel || '').toLowerCase()
14	    if (level === 'trace') logLevel = 'trace'
15	    else if (level === 'debug') logLevel = 'debug'
16	  })
17	  .catch(() => {})
