19	export function useWebSocket(sessionId: string | null) {
20	  const queryClient = useQueryClient()
21	  const wsRef = useRef<WebSocket | null>(null)
22	  const [connected, setConnected] = useState(false)
23	  const reconnectTimeoutRef = useRef<ReturnType<typeof setTimeout>>(undefined)
24	  const sessionIdRef = useRef(sessionId)
25	  sessionIdRef.current = sessionId
26	
27	  const sendMessage = useCallback((msg: WSClientMessage) => {
28	    const ws = wsRef.current
29	    if (ws && ws.readyState === WebSocket.OPEN) {
30	      ws.send(JSON.stringify(msg))
31	    }
32	  }, [])
33	
34	  // Send subscribe/unsubscribe when sessionId changes
35	  useEffect(() => {
36	    if (!connected) return
37	    if (sessionId) {
38	      sendMessage({ type: 'subscribe', sessionId })
39	      if (logLevel === 'debug' || logLevel === 'trace') {
40	        console.log(`[WS] Subscribing to session ${sessionId.slice(0, 8)}`)
41	      }
42	    } else {
43	      sendMessage({ type: 'unsubscribe' })
44	      if (logLevel === 'debug' || logLevel === 'trace') {
45	        console.log('[WS] Unsubscribed (no session selected)')
46	      }
47	    }
48	  }, [sessionId, connected, sendMessage])
49	
50	  const handleMessage = useCallback((msg: WSMessage) => {
51	    if (msg.type === 'event') {
52	      const event = msg.data as ParsedEvent
53	      const currentSessionId = sessionIdRef.current
54	      if (currentSessionId && event.sessionId === currentSessionId) {
55	        queryClient.setQueryData<ParsedEvent[]>(
56	          ['events', currentSessionId],
57	          (old) => old ? [...old, event] : [event],
58	        )
59	        if (logLevel === 'trace') {
60	          console.debug(`[WS] Event appended: ${event.type}/${event.subtype}${event.toolName ? ` tool:${event.toolName}` : ''}`)
61	        }
62	      }
63	    } else if (msg.type === 'session_update') {
64	      queryClient.invalidateQueries({ queryKey: ['sessions'] })
65	      if (logLevel === 'trace') {
66	        console.debug('[WS] Session update → invalidating sessions cache')
67	      }
68	    } else if (msg.type === 'project_update') {
69	      queryClient.invalidateQueries({ queryKey: ['projects'] })
70	      if (logLevel === 'trace') {
71	        console.debug('[WS] Project update → invalidating projects cache')
72	      }
73	    }
74	  }, [queryClient])
75	
76	  useEffect(() => {
77	    if (wsRef.current && wsRef.current.readyState <= WebSocket.OPEN) {
78	      return
79	    }
80	
81	    function connectWs() {
82	      // Guard against duplicate connections (e.g. from StrictMode reconnect races)
83	      if (wsRef.current && wsRef.current.readyState <= WebSocket.OPEN) return
84	
85	      try {
86	        const ws = new WebSocket(WS_URL)
87	        wsRef.current = ws
88	
89	        ws.onopen = () => {
90	          setConnected(true)
91	          console.log('[WS] Connected')
92	          // Subscribe to current session on reconnect
93	          const sid = sessionIdRef.current
94	          if (sid) {
95	            ws.send(JSON.stringify({ type: 'subscribe', sessionId: sid }))
96	            if (logLevel === 'debug' || logLevel === 'trace') {
97	              console.log(`[WS] Subscribing to session ${sid.slice(0, 8)} (on connect)`)
98	            }
99	          }
100	        }
101	
102	        ws.onmessage = (wsEvent) => {
103	          try {
104	            const msg: WSMessage = JSON.parse(wsEvent.data)
105	            handleMessage(msg)
106	          } catch {}
107	        }
108	
109	        ws.onclose = () => {
110	          // Only handle if this is still the active connection — avoids
111	          // clobbering a newer connection during StrictMode remount races
112	          if (wsRef.current !== ws) return
113	          setConnected(false)
114	          wsRef.current = null
115	          console.log('[WS] Disconnected, retrying in 3s...')
116	          reconnectTimeoutRef.current = setTimeout(connectWs, 3000)
117	        }
118	
119	        ws.onerror = () => {
120	          ws.close()
121	        }
122	      } catch {
123	        reconnectTimeoutRef.current = setTimeout(connectWs, 5000)
124	      }
125	    }
126	
127	    connectWs()
128	
129	    return () => {
130	      clearTimeout(reconnectTimeoutRef.current)
131	      wsRef.current?.close()
132	      wsRef.current = null
133	    }
134	  }, [handleMessage])
135	
136	  return { connected }
137	}
