4	async function fetchJson<T>(path: string, init?: RequestInit): Promise<T> {
5	  const res = await fetch(`${API_BASE}${path}`, init);
6	  if (!res.ok) throw new Error(`API error: ${res.status}`);
7	  return res.json();
8	}
