10	export const api = {
11	  getProjects: () => fetchJson<Project[]>('/projects'),
12	  getRecentSessions: (limit?: number) =>
13	    fetchJson<RecentSession[]>(`/sessions/recent${limit ? `?limit=${limit}` : ''}`),
14	  getSessions: (projectId: number) =>
15	    fetchJson<Session[]>(`/projects/${projectId}/sessions`),
16	  getSession: (sessionId: string) =>
17	    fetchJson<Session>(`/sessions/${encodeURIComponent(sessionId)}`),
18	  getAgent: (agentId: string) =>
19	    fetchJson<ServerAgent>(`/agents/${encodeURIComponent(agentId)}`),
20	  getAgents: (sessionId: string) =>
21	    fetchJson<ServerAgent[]>(`/sessions/${encodeURIComponent(sessionId)}/agents`),
22	  getEvents: (
23	    sessionId: string,
24	    filters?: {
25	      agentIds?: string[];
26	      type?: string;
27	      subtype?: string;
28	      search?: string;
29	      limit?: number;
30	      offset?: number;
31	    }
32	  ) => {
33	    const params = new URLSearchParams();
34	    if (filters?.agentIds?.length) params.set('agent_id', filters.agentIds.join(','));
35	    if (filters?.type) params.set('type', filters.type);
36	    if (filters?.subtype) params.set('subtype', filters.subtype);
37	    if (filters?.search) params.set('search', filters.search);
38	    if (filters?.limit) params.set('limit', String(filters.limit));
39	    if (filters?.offset) params.set('offset', String(filters.offset));
40	    const qs = params.toString();
41	    return fetchJson<ParsedEvent[]>(
42	      `/sessions/${encodeURIComponent(sessionId)}/events${qs ? `?${qs}` : ''}`
43	    );
44	  },
45	  getThread: (eventId: number) =>
46	    fetchJson<ParsedEvent[]>(`/events/${eventId}/thread`),
47	  deleteSession: (sessionId: string) =>
48	    fetch(`${API_BASE}/sessions/${encodeURIComponent(sessionId)}`, { method: 'DELETE' }),
49	  clearSessionEvents: (sessionId: string) =>
50	    fetch(`${API_BASE}/sessions/${encodeURIComponent(sessionId)}/events`, { method: 'DELETE' }),
51	  deleteProject: (projectId: number) =>
52	    fetchJson<void>(`/projects/${projectId}`, { method: 'DELETE' }),
53	  deleteAllData: () =>
54	    fetch(`${API_BASE}/data`, { method: 'DELETE' }),
55	  updateAgentMetadata: (agentId: string, data: { agentType?: string; slug?: string }) =>
56	    fetch(`${API_BASE}/agents/${encodeURIComponent(agentId)}/metadata`, {
57	      method: 'POST',
58	      headers: { 'Content-Type': 'application/json' },
59	      body: JSON.stringify(data),
60	    }),
61	  updateSessionSlug: (sessionId: string, slug: string) =>
62	    fetch(`${API_BASE}/sessions/${encodeURIComponent(sessionId)}/metadata`, {
63	      method: 'POST',
64	      headers: { 'Content-Type': 'application/json' },
65	      body: JSON.stringify({ slug }),
66	    }),
67	  renameProject: (projectId: number, name: string) =>
68	    fetch(`${API_BASE}/projects/${projectId}/rename`, {
69	      method: 'POST',
70	      headers: { 'Content-Type': 'application/json' },
71	      body: JSON.stringify({ name }),
72	    }),
73	};
