1	import { WebSocketServer, WebSocket } from 'ws'
2	import type { Server } from 'http'
3	import type { WSClientMessage } from './types'
4	import { config } from './config'
5	import { checkShutdown } from './consumer-tracker'
6	
7	const LOG_LEVEL = config.logLevel
8	
9	// Track which session each client is subscribed to
10	const clientSessions = new Map<WebSocket, string>()
11	const allClients = new Set<WebSocket>()
12	
13	export function attachWebSocket(server: Server) {
14	  const wss = new WebSocketServer({ server, path: '/api/events/stream' })
15	
16	  wss.on('connection', (ws) => {
17	    allClients.add(ws)
18	    console.log(`[WS] Client connected (${allClients.size} total)`)
19	
20	    ws.on('message', (raw) => {
21	      try {
22	        const msg: WSClientMessage = JSON.parse(raw.toString())
23	        if (msg.type === 'subscribe' && msg.sessionId) {
24	          const prev = clientSessions.get(ws)
25	          clientSessions.set(ws, msg.sessionId)
26	          if (LOG_LEVEL === 'debug' || LOG_LEVEL === 'trace') {
27	            const prevInfo = prev ? ` (was: ${prev.slice(0, 8)})` : ''
28	            console.log(`[WS] Client subscribed to session ${msg.sessionId.slice(0, 8)}${prevInfo}`)
29	          }
30	        } else if (msg.type === 'unsubscribe') {
31	          const prev = clientSessions.get(ws)
32	          clientSessions.delete(ws)
33	          if (LOG_LEVEL === 'debug' || LOG_LEVEL === 'trace') {
34	            console.log(`[WS] Client unsubscribed${prev ? ` from session ${prev.slice(0, 8)}` : ''}`)
35	          }
36	        }
37	      } catch {}
38	    })
39	
40	    ws.on('close', () => {
41	      allClients.delete(ws)
42	      clientSessions.delete(ws)
43	      console.log(`[WS] Client disconnected (${allClients.size} remaining)`)
44	      checkShutdown()
45	    })
46	
47	    ws.on('error', () => {
48	      allClients.delete(ws)
49	      clientSessions.delete(ws)
50	    })
51	  })
52	
53	  console.log('[WS] WebSocket enabled on /api/events/stream')
54	}
55	
56	/** Send a message only to clients subscribed to a specific session */
57	export function broadcastToSession(sessionId: string, message: object): void {
58	  const json = JSON.stringify(message)
59	  for (const [client, subSessionId] of clientSessions) {
60	    if (subSessionId === sessionId && client.readyState === WebSocket.OPEN) {
61	      try {
62	        client.send(json)
63	      } catch {
64	        allClients.delete(client)
65	        clientSessions.delete(client)
66	      }
67	    }
68	  }
69	}
70	
71	/** Send a message to ALL connected clients (for global updates) */
72	export function broadcastToAll(message: object): void {
73	  const json = JSON.stringify(message)
74	  for (const client of allClients) {
75	    if (client.readyState === WebSocket.OPEN) {
76	      try {
77	        client.send(json)
78	      } catch {
79	        allClients.delete(client)
80	        clientSessions.delete(client)
81	      }
82	    }
83	  }
84	}
85	
86	export function getClientCount(): number {
87	  return allClients.size
88	}
